import React from 'react';

const AdminPanel = ({ rooms, threshold, setThreshold }) => {
    const checkedRooms = rooms.filter(r => r.status === 'checked').length;
    const dndRooms = rooms.filter(r => r.status === 'dnd').length;
    const totalRooms = rooms.length;

    return (
        <div className="page-content fade-in">
            <h2 className="page-title">Management</h2>

            <div className="admin-stats-grid">
                <div className="stat-card">
                    <span className="stat-value" style={{color: 'var(--success)'}}>{checkedRooms}</span>
                    <span className="stat-label">Готово</span>
                </div>
                <div className="stat-card">
                    <span className="stat-value" style={{color: 'var(--danger)'}}>{dndRooms}</span>
                    <span className="stat-label">DND</span>
                </div>
            </div>

            <div className="admin-settings-section">
                <h3>Сроки годности</h3>
                <div className="threshold-buttons">
                    {[30, 60, 90, 180].map(days => (
                        <button
                            key={days}
                            className={`t-btn ${threshold === days ? 'active' : ''}`}
                            onClick={() => setThreshold(days)}
                        >
                            {days} ДН
                        </button>
                    ))}
                </div>
                <p style={{fontSize: '10px', color: '#999', marginTop: '15px', textAlign: 'center'}}>
                    Отчет будет фильтровать товары, срок которых менее {threshold} дней.
                </p>
            </div>

            <div style={{textAlign: 'center', marginBottom: '30px'}}>
                <p style={{fontSize: '11px', color: '#666'}}>Всего номеров в базе: {totalRooms}</p>
            </div>

            <button className="btn-download" onClick={() => alert('Excel отчет генерируется...')}>
                📥 СКАЧАТЬ ОТЧЕТ
            </button>
        </div>
    );
};

export default AdminPanel;
